<?php
namespace Database\Seeders;use App\Models\Plan;use Illuminate\Database\Seeder;
class PlanSeeder extends Seeder{public function run():void{$plans=[['Starter','starter',19,190,'USD',5,3,500,100,[['limited_ai','Limited AI','true',true]]],['Pro','pro',49,490,'USD',15,20,5120,1000,[['ai_daily_summary','AI daily summary','true',true]]],['Business','business',149,1490,'USD',50,200,51200,5000,[['advanced_reports','Advanced reports','true',true],['weekly_ai_summary','Weekly AI summary','true',true]]],['Enterprise','enterprise',0,null,'USD',null,null,null,null,[['private_cloud','Private cloud','true',true],['local_ai','Local AI','true',true]]]];foreach($plans as[$name,$slug,$monthly,$yearly,$currency,$users,$projects,$storage,$ai,$features]){$plan=Plan::updateOrCreate(['slug'=>$slug],['name'=>$name,'monthly_price'=>$monthly,'yearly_price'=>$yearly,'currency'=>$currency,'user_limit'=>$users,'project_limit'=>$projects,'storage_limit_mb'=>$storage,'ai_monthly_quota'=>$ai,'is_public'=>$slug!=='enterprise','is_active'=>true]);foreach($features as[$key,$label,$value,$enabled])$plan->features()->updateOrCreate(['feature_key'=>$key],['feature_name'=>$label,'value'=>$value,'enabled'=>$enabled]);}}}
